// Helper functions to work with curriculum
export const getUnits = () => CURRICULUM_DATA.map(u => ({ id: u.id, name: u.name }));

export const getTopics = (unitId) => {
  const unit = CURRICULUM_DATA.find(u => u.id === unitId);
  return unit ? unit.topics.map(t => ({ id: t.id, name: t.name })) : [];
};

export const getSubtopics = (unitId, topicId) => {
  const unit = CURRICULUM_DATA.find(u => u.id === unitId);
  if (!unit) return [];
  const topic = unit.topics.find(t => t.id === topicId);
  return topic ? topic.subtopics.map(s => ({ id: s.id, name: s.name })) : [];
};

export const getUnitName = (unitId) => {
  const unit = CURRICULUM_DATA.find(u => u.id === unitId);
  return unit ? unit.name : '';
};

export const getTopicName = (unitId, topicId) => {
  const unit = CURRICULUM_DATA.find(u => u.id === unitId);
  if (!unit) return '';
  const topic = unit.topics.find(t => t.id === topicId);
  return topic ? topic.name : '';
};

export const getSubtopicName = (unitId, topicId, subtopicId) => {
  const unit = CURRICULUM_DATA.find(u => u.id === unitId);
  if (!unit) return '';
  const topic = unit.topics.find(t => t.id === topicId);
  if (!topic) return '';
  const subtopic = topic.subtopics.find(s => s.id === subtopicId);
  return subtopic ? subtopic.name : '';
};

